INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1032, 186497, 6, 1538, '缘尽情未了', '街道 空空荡荡，房间 空无一人，一丝伤感，萦绕我心头。在愈显局促的房间里，我孤独一人。不知道为什么，不知道往昔去了何方，那些在一起歌唱的日子。我至今仍拥抱着永恒。我寄情于字里行间，埋首于工作不竭，与好友尽情欢笑，还是止不住对你的思念。 
<br>    紧身衣下是她五尺十寸的高佻身段，清澈纯真的眼神令每个盯着她的人无法相信她竟是我的女孩。我早应该明白当我离开她追求人生时自己所犯下的天大的错误，他们说我总要等到失去才会开始思念。看来我爱你的方式很失败，而你已将爱全部都带走，我该怎么走过你的身边，当你看起来如此明艳动人。这不是道别，即使我目送你离去，这不是道别，我发誓我不哭，尽管泪已盈眶。若是其她女孩，我会让她离开，若是其她女孩，我不会感到悲哀，告诉我怎么才叫做好男人？对你心甘情愿付出真心，因你的陪伴而微笑，因你的离去而流泪，如果你知道如何做个好男人，我愿意就那样爱着你。唤不回你的心，我不想因此而迷失，我不愿过没有你的生活-----如果我可以控制自己！如果我能再一次占领你的心，我不会轻易让你走，会用我心的呐喊对你说------我会改变所以的错，让我们从头爱过！', '街道 空空荡荡，房间 空无一人，一丝伤感，萦绕我心头。在愈显局促的房间里，我孤独一人。不知道为什么，不知道往昔去了何方，那些在一起歌唱的日子。我至今仍拥抱着永恒。我寄情于字里行间，埋首于工作不竭，与好友尽情欢笑，还是止不住对你的思念。

紧身衣下是她五尺十寸的高佻身段，清澈纯真的眼神令每个盯着她的人无法相信她竟是我的女孩。我早应该明白当我离开她追求人生时自己所犯下的天大的错误，他们说我总要等到失去才会开始思念。看来我爱你的方式很失败，而你已将爱全部都带走，我该怎么走过你的身边，当你看起来如此明艳动人。这不是道别，即使我目送你离去，这不是道别，我发誓我不哭，尽管泪已盈眶。若是其她女孩，我会让她离开，若是其她女孩，我不会感到悲哀，告诉我怎么才叫做好男人？对你心甘情愿付出真心，因你的陪伴而微笑，因你的离去而流泪，如果你知道如何做个好男人，我愿意就那样爱着你。唤不回你的心，我不想因此而迷失，我不愿过没有你的生活-----如果我可以控制自己！如果我能再一次占领你的心，我不会轻易让你走，会用我心的呐喊对你说------我会改变所以的错，让我们从头爱过！', NULL, '2002-10-19 02:07:00', 1, '20021114140213_bbsid_186497_board_6_6c81c37ccb.html', '20021114140213');
